sql:
SELECT c.category_name, c.description
FROM categories c
JOIN category_character_map cm ON c.category_id = cm.category_id;

SELECT DISTINCT c.category_name, c.description
FROM categories c
JOIN category_character_map cm ON c.category_id = cm.category_id;

SELECT c.*, cm.char_id
FROM categories c
LEFT JOIN category_character_map cm ON c.category_id = cm.category_id;

SELECT DISTINCT category_name, description
FROM categories
ORDER BY category_name ASC;

SELECT COUNT(DISTINCT language_id)
FROM programming_languages
WHERE language_id NOT IN (SELECT language_id FROM unicode_properties);

SELECT COUNT(DISTINCT c.category_name)
FROM categories c
JOIN programming_languages pl ON c.category_name = pl.language_name;

external_knowledge:
'control codes' is a category in the unicode character set, which refers to characters that are not used to represent printable information but rather control the interpretation of other characters or the output stream itself; 
 Unicode properties are characteristics that can be used to distinguish or categorize Unicode characters; 
 Unicode values are unique numerical values assigned to each character in the Unicode character set.
